parameters.jsCode:
const rawContent = $input.first().json.choices[0].message.content.trim();

// Log raw content for debugging
console.log('Raw Groq response:', rawContent);

let parsed;
try {
  parsed = JSON.parse(rawContent);
} catch (e) {
  // Try cleaning markdown fences
  const cleaned = rawContent.replace(/```json|```/gi, '').trim();
  try {
    parsed = JSON.parse(cleaned);
  } catch (e2) {
    throw new Error('Groq returned invalid JSON: ' + rawContent);
  }
}

// Force lead_score to number
parsed.lead_score = parseInt(parsed.lead_score, 10);

// If still invalid, default to 50
if (isNaN(parsed.lead_score) || parsed.lead_score < 1 || parsed.lead_score > 100) {
  parsed.lead_score = 50;
}

// Default status if missing
if (!parsed.status || !['qualified', 'unqualified'].includes(parsed.status)) {
  parsed.status = 'unqualified';
}

// Try all possible Tally data paths
const webhookData = $('Tally Inbound Form').first().json;
const fields = 
  webhookData?.data?.fields ||
  webhookData?.body?.data?.fields ||
  webhookData?.body?.fields ||
  webhookData?.fields ||
  [];

const getField = (label) => {
  const field = fields.find(f => f.label === label);
  return field ? field.value : 'N/A';
};

return [{
  json: {
    status: parsed.status,
    lead_score: parsed.lead_score,
    Name: getField('Name'),
    Email: getField('Email'),
    Budget: getField('Budget'),
    Need: getField('What do you need help with?')
  }
}];

